// ── COLOR SYSTEM ────────────────────────────────────────────────
// Every color is mathematically derived from one hero hex: #6A001E
// Hero HSL: (343°, 100%, 21%)
//
// Domain colors: Hue rotated at harmonic intervals from hero
// UI surfaces: Hero hue, desaturated, shifted in lightness
// Text: Hero hue, heavily desaturated, high lightness
// Accents: Hero hue, moderate saturation, mid lightness
//
// This guarantees total chromatic coherence.

const HERO_HEX = "#6A001E";

// ── Color math utilities ──
function hexToHSL(hex) {
  let r = parseInt(hex.slice(1, 3), 16) / 255;
  let g = parseInt(hex.slice(3, 5), 16) / 255;
  let b = parseInt(hex.slice(5, 7), 16) / 255;
  const max = Math.max(r, g, b), min = Math.min(r, g, b);
  let h = 0, s = 0, l = (max + min) / 2;
  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = ((g - b) / d + (g < b ? 6 : 0)) / 6; break;
      case g: h = ((b - r) / d + 2) / 6; break;
      case b: h = ((r - g) / d + 4) / 6; break;
    }
  }
  return [Math.round(h * 360), Math.round(s * 100), Math.round(l * 100)];
}

function hslToHex(h, s, l) {
  h = ((h % 360) + 360) % 360;
  s = Math.max(0, Math.min(100, s)) / 100;
  l = Math.max(0, Math.min(100, l)) / 100;
  const c = (1 - Math.abs(2 * l - 1)) * s;
  const x = c * (1 - Math.abs((h / 60) % 2 - 1));
  const m = l - c / 2;
  let r = 0, g = 0, b = 0;
  if (h < 60) { r = c; g = x; }
  else if (h < 120) { r = x; g = c; }
  else if (h < 180) { g = c; b = x; }
  else if (h < 240) { g = x; b = c; }
  else if (h < 300) { r = x; b = c; }
  else { r = c; b = x; }
  const toHex = (v) => Math.round((v + m) * 255).toString(16).padStart(2, "0");
  return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
}

// ── Derive the complete system from hero ──
const [HERO_H, HERO_S, HERO_L] = hexToHSL(HERO_HEX);

// Primary accent: white. The hero burgundy lives in the system, not on the surface.
const ACCENT = "#FFFFFF";
const ACCENT_DIM = hslToHex(HERO_H, 6, 40);

// UI palette: all derived from hero hue
// Near-neutral with faint warm tint. Formality through restraint.
const UI = {
  bg:          hslToHex(HERO_H, 12, 5),      // deep dark, faintly warm
  surface:     hslToHex(HERO_H, 10, 9),      // cards/elevated
  border:      hslToHex(HERO_H, 8, 16),      // subtle dividers
  borderFaint: hslToHex(HERO_H, 6, 12),      // very subtle
  text:        hslToHex(HERO_H, 5, 88),      // primary text — near-white, barely warm
  textMid:     hslToHex(HERO_H, 4, 68),      // secondary text — clearly legible
  textDim:     hslToHex(HERO_H, 4, 50),      // tertiary/labels — readable
  textFaint:   hslToHex(HERO_H, 3, 30),      // ghost text — discernible
};

// Domain colors: near-neutral, hues assigned by MEANING not math
// Harvey-inspired: formal, restrained. The hero burgundy is the ONLY saturated color.
// Even at 12% saturation, the hue must feel right for the domain.
const DOMAIN_SAT = 12;
const DOMAIN_LIT = 62;
const DOMAIN_HUES = {
  body:      HERO_H,       // 343° — rose/warm. Blood, vitality, the physical.
  mind:      220,          // 220° — cool blue. Cerebral, clarity, thought.
  character: 35,           // 35°  — warm stone. Grounded, moral weight, earthy.
  finances:  150,          // 150° — faint green. Growth, ledgers, money.
  order:     200,          // 200° — steel/slate. Systems, cold precision.
  relations: 15,           // 15°  — warm copper. Human warmth, connection.
  purpose:   45,           // 45°  — amber/gold. Ambition, aspiration, fire.
};

const domainColor = (id, isDark = true) =>
  hslToHex(DOMAIN_HUES[id], DOMAIN_SAT, isDark ? DOMAIN_LIT : 35);
const domainColorDim = (id, isDark = true) =>
  hslToHex(DOMAIN_HUES[id], DOMAIN_SAT, (isDark ? DOMAIN_LIT : 35) * 0.3);

