const ALL_VIRTUES = DOMAINS.flatMap(d => d.virtues.map(v => ({ ...v, domainId: d.id, domainName: d.name, domainColor: d.color })));
const TOTAL_VIRTUES = ALL_VIRTUES.length;

// ── UTILITY FUNCTIONS ───────────────────────────────────────────

const getDateKey = (date) => date.toISOString().split("T")[0];
const getToday = () => getDateKey(new Date());

const getDayOfWeek = (dateStr) => {
  const d = new Date(dateStr + "T12:00:00");
  return ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][d.getDay()];
};

const getWeekDates = (offsetWeeks = 0) => {
  const now = new Date();
  const day = now.getDay();
  const monday = new Date(now);
  monday.setDate(now.getDate() - ((day + 6) % 7) + offsetWeeks * 7);
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    return getDateKey(d);
  });
};

const formatDate = (dateStr) => {
  const d = new Date(dateStr + "T12:00:00");
  return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
};

const formatDateFull = (dateStr) => {
  const d = new Date(dateStr + "T12:00:00");
  return d.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" });
};

// ── STORAGE ─────────────────────────────────────────────────────

const STORAGE_KEY = "alfred_data";

const loadData = () => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : {};
  } catch {
    return {};
  }
};

const saveData = (data) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
  } catch {}
};


// ── SUPABASE HELPERS ────────────────────────────────────────────

async function loadSupabaseData(userId) {
  const { data: rows, error } = await supabase
    .from("daily_logs")
    .select("date, virtues")
    .eq("user_id", userId)
    .order("date", { ascending: false });
  if (error) { console.error("Supabase load error:", error); return null; }
  return rows.reduce((acc, row) => { acc[row.date] = row.virtues; return acc; }, {});
}

async function migrateLocalStorageToSupabase(userId) {
  const localData = loadData();
  const dates = Object.keys(localData);
  if (dates.length === 0) return;
  const rows = dates.map(date => ({ user_id: userId, date, virtues: localData[date] }));
  const { error } = await supabase.from("daily_logs").upsert(rows, { onConflict: "user_id,date" });
  if (error) { console.error("Migration error:", error); return; }
  localStorage.removeItem(STORAGE_KEY);
}

// ── COMPONENTS ──────────────────────────────────────────────────

const ScoreRing = ({ score, size = 120, strokeWidth = 6, color = 'var(--alfred-accent)' }) => {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (score / 100) * circumference;

  return (
    <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
      <circle cx={size/2} cy={size/2} r={radius} fill="none" stroke="var(--alfred-border-faint)" strokeWidth={strokeWidth} />
      <circle
        cx={size/2} cy={size/2} r={radius} fill="none" stroke={color} strokeWidth={strokeWidth}
        strokeDasharray={circumference} strokeDashoffset={offset}
        strokeLinecap="round"
        style={{ transition: "stroke-dashoffset 0.8s cubic-bezier(0.4, 0, 0.2, 1)" }}
      />
    </svg>
  );
};

const VirtueRow = ({ virtue, checked, onToggle, domainColor: dc }) => (
  <div
    onClick={onToggle}
    className="flex items-center gap-4 py-3.5 cursor-pointer"
    style={{ borderBottom: "1px solid var(--alfred-border-faint)" }}
  >
    <Checkbox
      checked={checked}
      onClick={(e) => e.stopPropagation()}
      onCheckedChange={onToggle}
      style={checked ? { backgroundColor: dc, borderColor: dc } : {}}
    />
    <div className="flex-1 min-w-0">
      <div style={{
        fontFamily: "'DM Sans', sans-serif", fontSize: 13, fontWeight: 600,
        color: "var(--alfred-text)", letterSpacing: "0.02em"
      }}>{virtue.name}</div>
      <div style={{
        fontFamily: "'Harvey Serif', serif", fontSize: 13, color: "var(--alfred-text-mid)",
        marginTop: 2, fontStyle: "italic"
      }}>{virtue.question}</div>
    </div>
  </div>
);

// ── VIEWS ───────────────────────────────────────────────────────

const DailyLedger = ({ date, data, setData, isDark, user }) => {
  const dateKey = date;
  const dayData = data[dateKey] || {};

  const toggleVirtue = async (virtueId) => {
    const newData = { ...data };
    if (!newData[dateKey]) newData[dateKey] = {};
    newData[dateKey] = { ...newData[dateKey], [virtueId]: !newData[dateKey][virtueId] };
    setData(newData);  // optimistic update

    if (user) {
      const { error } = await supabase.from("daily_logs").upsert(
        { user_id: user.id, date: dateKey, virtues: newData[dateKey] },
        { onConflict: "user_id,date" }
      );
      if (error) { console.error("Write error:", error); setData(data); }
    } else {
      saveData(newData);
    }
  };

  const checked = Object.values(dayData).filter(Boolean).length;
  const score = Math.round((checked / TOTAL_VIRTUES) * 100);
  const isPerfect = checked === TOTAL_VIRTUES;
  const accentColor = isDark ? "#FFFFFF" : "#6A001E";

  return (
    <div>
      <div style={{ textAlign: "center", marginBottom: 40 }}>
        <div style={{
          fontFamily: "'Harvey Serif', serif", fontSize: 14, color: "var(--alfred-text-dim)",
          letterSpacing: "0.15em", textTransform: "uppercase", marginBottom: 8
        }}>
          {formatDateFull(dateKey)}
        </div>
        <div style={{ position: "relative", display: "inline-block", margin: "16px 0" }}>
          <ScoreRing score={score} size={140} strokeWidth={5} color={isPerfect ? accentColor : "var(--alfred-accent-dim)"} />
          <div style={{
            position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)",
            textAlign: "center"
          }}>
            <div style={{
              fontFamily: "'DM Sans', sans-serif", fontSize: 32, fontWeight: 700,
              color: isPerfect ? "var(--alfred-accent)" : "var(--alfred-text)", lineHeight: 1
            }}>{score}</div>
            <div style={{
              fontFamily: "'DM Sans', sans-serif", fontSize: 10, color: "var(--alfred-text-dim)",
              letterSpacing: "0.1em"
            }}>/ 100</div>
          </div>
        </div>
        <div style={{
          fontFamily: "'DM Sans', sans-serif", fontSize: 12,
          color: isPerfect ? "var(--alfred-accent)" : "var(--alfred-text-mid)",
          letterSpacing: "0.05em"
        }}>
          {checked} / {TOTAL_VIRTUES} virtues{isPerfect ? " — PERFECT DAY ✦" : ""}
        </div>
      </div>

      {DOMAINS.map(domain => {
        const dc = domainColor(domain.id, isDark);
        const dcDim = domainColorDim(domain.id, isDark);
        const domainVirtues = domain.virtues;
        const domainChecked = domainVirtues.filter(v => dayData[v.id]).length;
        const domainPerfect = domainChecked === domainVirtues.length;

        return (
          <div key={domain.id} style={{ marginBottom: 32 }}>
            <div style={{
              display: "flex", alignItems: "center", justifyContent: "space-between",
              marginBottom: 8, paddingBottom: 8, borderBottom: `1px solid ${dcDim}`
            }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ color: dc, fontSize: 16 }}>{domain.icon}</span>
                <span style={{
                  fontFamily: "'Harvey Serif', serif", fontSize: 20, color: dc,
                  fontWeight: 500
                }}>{domain.name}</span>
              </div>
              <div style={{
                fontFamily: "'DM Sans', sans-serif", fontSize: 11,
                color: domainPerfect ? dc : "var(--alfred-text-dim)",
                letterSpacing: "0.05em"
              }}>
                {domainChecked}/{domainVirtues.length}
                {domainPerfect && " ✓"}
              </div>
            </div>
            <div style={{
              fontFamily: "'Harvey Serif', serif", fontSize: 13,
              color: "var(--alfred-text-dim)", fontStyle: "italic", marginBottom: 8
            }}>{domain.description}</div>
            {domainVirtues.map(virtue => (
              <VirtueRow
                key={virtue.id}
                virtue={virtue}
                checked={!!dayData[virtue.id]}
                onToggle={() => toggleVirtue(virtue.id)}
                domainColor={dc}
              />
            ))}
          </div>
        );
      })}
    </div>
  );
};

